sp_widget.client_script:
api.controller = function() {

    var c = this;

    /* Initialization */

    c.rule = {};
    c.tables = c.data.tables || [];
    c.fields = [];
    c.aggregationTypes = c.data.aggregationTypes || [];
    c.rule_sys_id = "";


    /* Load fields when Target Table changes */

    c.loadFields = function() {

        if (!c.rule.target_table)
            return;

        c.server.get({
            action: "getFields",
            target_table: c.rule.target_table
        }).then(function(response) {

            console.log("Fields loaded:", response.data.fields);

            if (response.data && response.data.fields)
                c.fields = response.data.fields;
            else
                c.fields = [];

        });

    };


    /* Save Rule */

    c.saveRule = function() {

        if (!c.rule.rule_name) {
            alert("Rule Name is required");
            return;
        }

        if (!c.rule.target_table) {
            alert("Please select Target Table");
            return;
        }

        if (!c.rule.target_field) {
            alert("Please select Target Field");
            return;
        }

        c.server.get({
            action: "saveRule",
            rule: c.rule
        }).then(function(response) {

            console.log("Save response:", response);

            if (response.data && response.data.rule_sys_id) {

                c.rule_sys_id = response.data.rule_sys_id;

                alert("Rule Created Successfully");

            }

        });

    };

};

sp_widget.script:
(function() {

    /* Initial load */

    if (!input) {

        data.tables = [];
        data.aggregationTypes = [];

        /* Load Target Tables */

        var grObj = new GlideRecordSecure("x_ctans_incentnow_data_model_object");
        grObj.query();

        while (grObj.next()) {

            data.tables.push({
                label: grObj.getDisplayValue(),
                value: grObj.getUniqueValue()
            });

        }


        /* Load Aggregation Type Choices */

        var grChoice = new GlideRecordSecure("sys_choice");

        grChoice.addQuery("name", "x_ctans_incentnow_rule_master");
        grChoice.addQuery("element", "aggregation_type");
        grChoice.addQuery("inactive", false);
        grChoice.orderBy("sequence");
        grChoice.query();

        while (grChoice.next()) {

            data.aggregationTypes.push({
                label: grChoice.getValue("label"),
                value: grChoice.getValue("value")
            });

        }

        return;
    }



    /* Load Target Fields */

    if (input.action == "getFields") {

        data.fields = [];

        var grField = new GlideRecordSecure("x_ctans_incentnow_metadata_mapping");

        grField.addQuery("data_model_object_id", input.target_table);
        grField.query();

        while (grField.next()) {

            data.fields.push({
                label: grField.getValue("source_field_name"),
                value: grField.getUniqueValue()
            });

        }

        return;
    }



    /* Save Rule */

    if (input.action == "saveRule") {

        var rule = new GlideRecordSecure("x_ctans_incentnow_rule_master");
        rule.initialize();

        rule.rule_name = input.rule.rule_name || "";
        rule.target_table = input.rule.target_table || "";
        rule.target_field = input.rule.target_field || "";
        rule.aggregation_type = input.rule.aggregation_type || "";
        rule.rule_type = input.rule.rule_type || "";
        rule.split_method = input.rule.split_method || "";
        rule.split_percentage = input.rule.split_percentage || "";
        rule.description = input.rule.description || "";
        rule.active = true;

        var ruleSysId = rule.insert();

        data.rule_sys_id = ruleSysId;

        return;
    }

})();
